Plot.plot({
  width: 560,
  height: 480,
  marginLeft: 70,
  marginRight: 10,
  marginBottom: 60,
  style: { fontSize: "12px" },
  x: {
    tickFormat: d =&gt; `${Math.abs(d).toFixed(1)}`,
    label: `Población en ${año_dep} (%)  (Total: ${total_dep.toLocaleString('de-DE')})`,
    labelOffset: 50,
    domain: [-5, 5],
    grid: true
